use crate::core_crypto::prelude::*;

/// Pre-computed table that maps every odd value in `[1, 2N)` to its representation as
/// `±base^k mod 2N`.
///
/// Because the Galois group of `Z[X]/(X^N+1)` is generated by `σ_{base}`, every odd exponent
/// in the range `[1, 2N)` can be written as `±base^k` for some `k`.
/// `BaseDecomposer` builds
/// this bijection at construction time and then answers queries in O(1) via
/// [`decompose_in_base`](BaseDecomposer::decompose_in_base).
///
/// **Prerequisite**: `base` must be a primitive root of `Z*_{2N}` (i.e. its order modulo `2N`
/// must equal `N`), otherwise not all odd values will be covered and construction will panic.
pub struct BaseDecomposer {
    polynomial_size: PolynomialSize,
    table: Vec<Decomposition>,
}

/// The result of decomposing an odd monomial exponent as `±base^base_exponent mod 2N`.
#[derive(Copy, Clone, Default, Debug)]
pub struct Decomposition {
    pub base_exponent: u16,
    pub negative: bool,
}

impl BaseDecomposer {
    /// Builds the decomposition table for `base` in the ring `Z[X]/(X^N+1)`.
    ///
    /// Iterates over `base^0, base^1, …, base^(N/2-1)` modulo `2N`, recording each value and its
    /// negation `2N - base^k`. Together these cover all `N` odd residues in `[1, 2N)`.
    ///
    /// Panics if `base` is not a primitive root of `Z*_{2N}` (i.e. some table slots would remain
    /// unfilled because the orbit of `base` does not span the whole group).
    pub fn new(base: u64, polynomial_size: PolynomialSize) -> Self {
        let mut table = vec![Decomposition::default(); polynomial_size.0];

        let mut table_initialized = vec![false; polynomial_size.0];

        let m = 2 * polynomial_size.0 as u64;

        let mut power = 1;

        for base_exponent in 0..polynomial_size.0 / 2 {
            // power = base^base_exponent
            {
                assert!(power % 2 == 1);
                let index = power as usize / 2;

                assert!(!table_initialized[index]);
                table_initialized[index] = true;

                table[index] = Decomposition {
                    base_exponent: base_exponent as u16,
                    negative: false,
                };
            }

            let minus_power = (m - power) % m;

            {
                assert!(minus_power % 2 == 1);
                let index = minus_power as usize / 2;

                assert!(!table_initialized[index]);
                table_initialized[index] = true;

                table[index] = Decomposition {
                    base_exponent: base_exponent as u16,
                    negative: true,
                };
            }

            power = (power * base) % m;
        }

        for i in table_initialized {
            assert!(i);
        }

        Self {
            polynomial_size,
            table,
        }
    }

    /// Returns the [`Decomposition`] of `monomial_power` as `±base^k mod 2N`.
    ///
    /// `monomial_power` must be odd and lie in `[1, 2N)`.
    pub fn decompose_in_base(&self, monomial_power: u64) -> Decomposition {
        assert!(monomial_power < 2 * self.polynomial_size.0 as u64);
        assert!(monomial_power % 2 == 1);

        self.table[monomial_power as usize / 2]
    }
}

/// Computes `base^power mod modulus` by repeated multiplication.
pub fn compute_power(base: u64, power: u64, modulus: u64) -> u64 {
    let mut result = 1;
    for _ in 0..power {
        result = (result * base) % modulus
    }
    result
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_base_decomposer() {
        let polynomial_size = PolynomialSize(2048);

        let base = 5;

        let decomposer = BaseDecomposer::new(base, polynomial_size);

        let m = polynomial_size.0 as u64 * 2;

        for i in 0..2 * polynomial_size.0 {
            if i % 2 == 0 {
                continue;
            }
            let Decomposition {
                base_exponent,
                negative,
            } = decomposer.decompose_in_base(i as u64);

            let power = compute_power(base, base_exponent as u64, m);

            let power = if negative { (m - power) % m } else { power };

            assert_eq!(power, i as u64);
        }
    }
}
